#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, C;
        scanf("%d %d", &N, &C);
        int *coins = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &coins[i]);
        long long *dp = (long long *)calloc(C + 1, sizeof(long long));
        dp[0] = 1;
        for (int i = 0; i < N; ++i) {
            int d = coins[i];
            for (int x = d; x <= C; ++x) {
                dp[x] += dp[x - d];
                if (dp[x] >= MOD) dp[x] -= MOD;
            }
        }
        printf("%lld\n", dp[C] % MOD);
        free(coins);
        free(dp);
    }
    return 0;
}

