const fs = require('fs');
const MOD = 1000000007n;
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(BigInt);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  const C = Number(input[idx++]);
  let coins = [];
  for (let i = 0; i < N; ++i) coins.push(Number(input[idx++]));
  let dp = new Array(C + 1).fill(0n);
  dp[0] = 1n;
  for (let d of coins) {
    for (let x = d; x <= C; ++x) {
      dp[x] = (dp[x] + dp[x - d]) % MOD;
    }
  }
  outputs.push((dp[C] % MOD).toString());
}
console.log(outputs.join('\n'));
